#!/usr/bin/env node
// Spike 1: Node-side counterpart to the in-browser harness.
//
// Reads a substrate workbook .html file (whether generated by
// generate-test-file.mjs or hand-built) and confirms:
//   • <wb-meta>, <wb-snapshot:*>, <wb-wal> elements are extractable
//     by simple regex against the file bytes (no DOM parser needed)
//   • Each snapshot's CID matches the recomputed hash of its bytes
//   • WAL parses as JSON and seq is monotonic
//
// Confirms the runtime can extract structural sections from raw bytes
// without depending on the browser's DOM parser to honor binary
// regions — which matters when we later layer in real binary blobs
// or move to opaque-encoded WAL entries.
//
// Usage:
//   node test-extract-node.mjs ./out/spike-parser-test.html

import { readFileSync } from "node:fs";
import { createHash } from "node:crypto";

const path = process.argv[2];
if (!path) {
  console.error("Usage: test-extract-node.mjs <file.html>");
  process.exit(1);
}

const raw = readFileSync(path, "utf8");
console.log(`Read ${path}: ${(raw.length / 1024 / 1024).toFixed(2)} MB`);

function blake3Hex(bytes) {
  return createHash("sha256").update(bytes).digest("hex").slice(0, 24);
}

// Extract a <script id="..."> block's textContent via regex.
// Greedy on the body so trailing > inside doesn't terminate early.
function extractScriptById(html, id) {
  const idEsc = id.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const re = new RegExp(
    `<script[^>]*\\bid="${idEsc}"[^>]*>([\\s\\S]*?)</script>`,
    "i",
  );
  const m = html.match(re);
  return m ? m[1] : null;
}

let pass = 0, fail = 0;
function check(name, ok, detail) {
  console.log(`${ok ? "✓" : "✗"} ${name}${detail ? ": " + detail : ""}`);
  if (ok) pass++; else fail++;
}

// 1. wb-meta extractable + parseable
const metaText = extractScriptById(raw, "wb-meta");
check("wb-meta extractable", metaText !== null);
let meta;
try {
  meta = JSON.parse(metaText);
  check("wb-meta JSON parses", true, `workbook_id=${meta.workbook_id}`);
} catch (e) {
  check("wb-meta JSON parses", false, e.message);
  process.exit(1);
}

// 2. Each snapshot retrievable + CID matches
for (const exp of meta.expected.snapshots) {
  const id = "wb-snapshot:" + exp.name;
  const b64 = extractScriptById(raw, id)?.replace(/\s/g, "");
  check(`snapshot ${exp.name} extractable`, !!b64, `len=${b64?.length ?? 0}`);
  if (!b64) continue;
  check(`snapshot ${exp.name} length matches expected`,
    b64.length === exp.b64Len,
    `${b64.length} vs ${exp.b64Len}`);
  const bytes = Buffer.from(b64, "base64");
  const cid = "spike-" + blake3Hex(bytes);
  check(`snapshot ${exp.name} CID match`, cid === exp.cid, `${cid} vs ${exp.cid}`);
}

// 3. WAL extracts + parses + seq monotonic + parent-CID chain integrity
const walText = extractScriptById(raw, "wb-wal");
check("wb-wal extractable", walText !== null);
let wal;
try {
  wal = JSON.parse(walText);
  check("wb-wal JSON parses", true, `${wal.length} ops`);
} catch (e) {
  check("wb-wal JSON parses", false, e.message);
  process.exit(1);
}

let monotonic = true;
for (let i = 1; i < wal.length; i++) {
  if (wal[i].seq <= wal[i - 1].seq) { monotonic = false; break; }
}
check("WAL seq monotonic", monotonic);

const lastCid = { ...meta.expected.snapshotCidByName };
let chainOk = true, brokeAt = -1;
for (const op of wal) {
  const expected = lastCid[op.target];
  if (op.parent_cid !== expected) { chainOk = false; brokeAt = op.seq; break; }
  lastCid[op.target] = op.cid;
}
check("WAL parent-CID chain", chainOk, chainOk ? "" : `broke at seq=${brokeAt}`);

console.log(`\n${pass} passed, ${fail} failed`);
process.exit(fail > 0 ? 1 : 0);
